import React from "react";

export default function Footer() {
    return (
        <footer className="border-t border-white/10 py-8 mt-10">
            <div className="max-w-7xl mx-auto px-6 text-center">
                <p className="text-white/60 text-sm">
                    © {new Date().getFullYear()} TrendTracker Pro. All rights reserved.
                </p>

                <p className="text-white/40 text-xs mt-2">
                    Trading involves risk. This platform provides educational market
                    information and signals only.
                </p>
            </div>
        </footer>
    );
}
